import{_ as e,o as s,c as i,a2 as t}from"./chunks/framework.BKG_UbFK.js";const k=JSON.parse('{"title":"Super Admin","description":"","frontmatter":{},"headers":[],"relativePath":"ru/features/super-admin.md","filePath":"ru/features/super-admin.md"}'),c={name:"ru/features/super-admin.md"};function d(n,a,l,r,o,p){return s(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="super-admin" tabindex="-1">Super Admin <a class="header-anchor" href="#super-admin" aria-label="Permalink to &quot;Super Admin&quot;">​</a></h1><p>Роль <code>super_admin</code> создаётся автоматически командой <code>clearance:install</code> и поддерживается в синхронизации со всеми разрешениями <code>clearance-*</code>.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Install and make user ID 1 a super admin</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --user=1</span></span></code></pre></div><p>См. <a href="/clearance-docs/ru/guide/installation.html">руководство по установке</a> и <a href="/clearance-docs/ru/api/artisan-commands.html">справочник команд Artisan</a> для полного списка флагов установщика.</p><h2 id="обход-gate-опционально" tabindex="-1">Обход Gate (опционально) <a class="header-anchor" href="#обход-gate-опционально" aria-label="Permalink to &quot;Обход Gate (опционально)&quot;">​</a></h2><p><code>super_admin_gate_bypass</code> управляет тем, обходит ли роль <code>super_admin</code> все проверки <code>can()</code> / <code>Gate::allows()</code> / политик Laravel глобально, через хук <code>Gate::before()</code>. По умолчанию: <code>false</code>. Обход опционален. Чтобы включить его:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;super_admin_gate_bypass&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span></code></pre></div><div class="danger custom-block"><p class="custom-block-title">Действует во всём приложении, а не только в панели</p><p>Если включено, любой пользователь, обладающий <code>super_admin</code>, пропускает <strong>все</strong> проверки Gate во всём приложении - не только проверки панели Clearance. Это затрагивает каждую проверку <code>can()</code>, <code>Gate::allows()</code> и политики в вашем приложении, а не только те, что определяет Clearance. Для более узкой области оставьте это выключенным и выдавайте разрешения явно.</p></div><h2 id="обнаружение-алиасов" tabindex="-1">Обнаружение алиасов <a class="header-anchor" href="#обнаружение-алиасов" aria-label="Permalink to &quot;Обнаружение алиасов&quot;">​</a></h2><p>Если в вашей базе данных уже есть роль с именем <code>super_admin</code>, <code>superadmin</code>, <code>super-admin</code>, <code>root</code> или <code>owner</code>, установщик обнаруживает её и интерактивно предлагает либо повысить её, либо создать отдельную роль <code>super_admin</code>. Используйте <code>--super-admin-role=NAME</code>, чтобы пропустить запрос:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --super-admin-role=owner</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Повышение неразрушающее</p><p>Повышение переименовывает роль на месте - все существующие назначения <code>model_has_roles</code> сохраняются благодаря внешнему ключу на <code>role_id</code>. Ни один пользователь не теряет существующее назначение роли во время повышения.</p></div><h2 id="доступ-к-панели-и-точечные-права-на-запись" tabindex="-1">Доступ к панели и точечные права на запись <a class="header-anchor" href="#доступ-к-панели-и-точечные-права-на-запись" aria-label="Permalink to &quot;Доступ к панели и точечные права на запись&quot;">​</a></h2><p>Перейдите на <code>/clearance</code> после установки. Доступ на чтение ко всей панели требует разрешения <code>clearance-access</code>, проверяемого через <code>can()</code>, никогда через <code>hasRole()</code>:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-access&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>Операции записи в каждом разделе защищены отдельным делегируемым разрешением - все они создаются <code>clearance:install</code> и назначаются <code>super_admin</code>:</p><table tabindex="0"><thead><tr><th>Разрешение</th><th>Контролирует</th></tr></thead><tbody><tr><td><code>clearance-permissions-write</code></td><td>Создание / редактирование / удаление разрешений</td></tr><tr><td><code>clearance-roles-write</code></td><td>Создание / редактирование / удаление ролей и их назначений разрешений</td></tr><tr><td><code>clearance-guards-write</code></td><td>Создание / редактирование / удаление guard&#39;ов</td></tr><tr><td><code>clearance-settings-write</code></td><td>Редактирование метаданных отображения, иконок, цветов, роли по умолчанию</td></tr><tr><td><code>clearance-users-write</code></td><td>Назначение / удаление ролей для конкретного пользователя</td></tr></tbody></table><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Grant a user write access to roles only:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-access&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-roles-write&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Предоставление узкого доступа</p><p>Скомбинируйте <code>clearance-access</code> ровно с одним разрешением <code>clearance-{section}-write</code>, чтобы дать пользователю (скажем, тимлиду) доступ на запись только к одному разделу панели - например, к ролям - не открывая при этом настройки, guard&#39;ы или управление пользователями.</p></div><p>Если строка точечного разрешения вообще не существует в базе данных (устаревшее состояние до появления seed&#39;а), проверка откатывается к <code>clearance-access</code> для обратной совместимости. На любом экземпляре, где уже был выполнен <code>clearance:install</code>, этот откат никогда не активируется.</p><h2 id="зарезервированные-разрешения-clearance" tabindex="-1">Зарезервированные разрешения <code>clearance-*</code> <a class="header-anchor" href="#зарезервированные-разрешения-clearance" aria-label="Permalink to &quot;Зарезервированные разрешения \`clearance-*\`&quot;">​</a></h2><p>Разрешения <code>clearance-*</code> зарезервированы: их нельзя создавать, переименовывать, удалять или добавлять к какой-либо роли иначе как через собственный процесс установки пакета - даже актором <code>super_admin</code> для самой роли <code>super_admin</code>.</p><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><ul><li><a href="/clearance-docs/ru/features/permissions.html">Разрешения</a> - общая панель CRUD для разрешений (исключает <code>clearance-*</code>).</li><li><a href="/clearance-docs/ru/features/roles.html">Роли</a> - назначение разрешений <code>clearance-*-write</code> пользовательской роли.</li><li><a href="/clearance-docs/ru/guide/security.html">Безопасность</a> - полная модель повышения привилегий и ceiling.</li></ul>`,24)])])}const u=e(c,[["render",d]]);export{k as __pageData,u as default};
